import React, { useState, useEffect } from 'react';
import { Menu, X, Phone } from 'lucide-react';
import { Link, useLocation } from 'react-router-dom';
import { NAV_ITEMS } from '../constants';
import { Button } from './Button';

export const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu on route change
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [location]);

  return (
    <header className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-brand-dark/95 backdrop-blur-sm py-2 shadow-xl' : 'bg-transparent py-4'}`}>
      <div className="container mx-auto px-4 flex justify-between items-center">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2 group">
           <div className="font-display font-bold text-3xl tracking-tighter text-brand-orange group-hover:scale-105 transition-transform">
             WERF<span className="text-white">PLAATS</span>
           </div>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden lg:flex items-center gap-8">
          {NAV_ITEMS.map((item) => (
            <Link 
              key={item.label} 
              to={item.href}
              className={`text-sm uppercase tracking-wide font-medium transition-colors ${
                location.pathname === item.href 
                  ? 'text-brand-orange' 
                  : 'text-white hover:text-brand-orange'
              }`}
            >
              {item.label}
            </Link>
          ))}
          <Button variant="primary" className="!py-2 !px-4 !text-sm">
            Boek een demo
          </Button>
        </nav>

        {/* Mobile Toggle */}
        <button 
          className="lg:hidden text-white"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X size={28} /> : <Menu size={28} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="lg:hidden absolute top-full left-0 w-full bg-brand-dark border-t border-gray-800 p-4 flex flex-col gap-4 shadow-2xl h-screen">
          {NAV_ITEMS.map((item) => (
            <Link 
              key={item.label} 
              to={item.href}
              className={`font-medium text-lg uppercase ${
                location.pathname === item.href ? 'text-brand-orange' : 'text-white'
              }`}
            >
              {item.label}
            </Link>
          ))}
          <Button variant="primary" className="w-full">
            Boek een demo
          </Button>
          <div className="flex items-center justify-center gap-2 text-white/70 text-sm mt-4">
             <Phone size={16} /> Bel direct: +31 6 12 34 56 78
          </div>
        </div>
      )}
    </header>
  );
};

